import{_ as o,o as a,c as e,ag as r,ah as s}from"./chunks/framework.D9bIGSBm.js";const g=JSON.parse('{"title":"代码检查点","description":"","frontmatter":{},"headers":[],"relativePath":"features/checkpoints.md","filePath":"features/checkpoints.md"}'),l={name:"features/checkpoints.md"};function i(n,t,c,p,d,h){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="代码检查点" tabindex="-1">代码检查点 <a class="header-anchor" href="#代码检查点" aria-label="Permalink to &quot;代码检查点&quot;">​</a></h1><p>代码检查点（即界面设置中的「<strong>回合代码快照</strong>」）是 LoongCode 的自动代码保护机制——每轮对话发送前，应用自动给工作区代码拍一份快照，以便你在编辑历史消息时可以选择将代码一并回滚到那个时间点。</p><blockquote><p>相关基础：<a href="/docs/features/conversation.html#编辑历史消息重跑">对话面板 → 编辑历史消息重跑</a></p></blockquote><hr><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p><strong>回合代码快照</strong>（Turn Code Snapshots）是一项自动保护功能：</p><ul><li>每次你发送消息（每个对话轮次开始前），LoongCode 会自动给工作区代码拍一份快照，以 git 机制存储在本地。Claude、Codex 与 OpenCode 三个 CLI 家族的任务均支持（Codex 与 OpenCode 自 v0.9.0 起）。</li><li>快照与对话消息的每一轮次绑定，每条历史用户消息对应一份快照（若快照存在）。</li><li>有了快照，你可以在编辑历史消息重跑时选择「同时回滚代码」，将工作区代码回到该消息发送前的状态。</li></ul><div class="tip custom-block"><p class="custom-block-title">需要已安装 git</p><p>回合代码快照依赖 git 存储，使用前请确保系统已安装 git 并且工作区是一个 git 仓库。</p></div><hr><h2 id="开关位置" tabindex="-1">开关位置 <a class="header-anchor" href="#开关位置" aria-label="Permalink to &quot;开关位置&quot;">​</a></h2><p><strong>设置 → 常规 → 回合代码快照</strong></p><p>此开关默认<strong>开启</strong>。关闭后，新的轮次将不再拍快照；已有快照不受影响。</p><p><img src="'+s+'" alt="截图：「设置 → 常规」页面，「回合代码快照」开关处于开启状态，下方显示说明文字"></p><hr><h2 id="如何查看是否有快照" tabindex="-1">如何查看是否有快照 <a class="header-anchor" href="#如何查看是否有快照" aria-label="Permalink to &quot;如何查看是否有快照&quot;">​</a></h2><p>在编辑任意历史用户消息时，「同时回滚代码」复选框：</p><ul><li><strong>可用</strong>：说明该轮次有可用快照</li><li><strong>不可用（置灰）</strong>：该消息没有代码快照，鼠标悬浮提示「此消息无代码快照」</li></ul><hr><h2 id="如何回滚代码" tabindex="-1">如何回滚代码 <a class="header-anchor" href="#如何回滚代码" aria-label="Permalink to &quot;如何回滚代码&quot;">​</a></h2><p>回滚代码是编辑历史消息的<strong>附加选项</strong>，详细操作步骤见<a href="/docs/features/conversation.html#编辑历史消息重跑">对话面板 → 编辑历史消息重跑</a>。简要流程：</p><ol><li>找到你想修改的历史用户消息，点击<strong>编辑</strong>按钮进入编辑态。</li><li>如果该消息有快照，勾选「<strong>同时回滚代码</strong>」复选框。 <ul><li>首次勾选时弹出确认提示，提醒你回滚的影响范围。</li><li>勾选后，消息下方自动展开 <strong>Diff 预览面板</strong>，列出本次回滚将变更的文件，每个文件可点击展开查看逐行差异。</li></ul></li><li>确认 Diff 预览无误后，修改消息内容并发送。</li><li>LoongCode 先恢复代码快照，再以修改后的消息重新运行。</li></ol><div class="tip custom-block"><p class="custom-block-title">回滚前会自动存安全快照</p><p>执行回滚前，LoongCode 会自动存一份「可恢复」的安全快照，以防误操作。</p></div><div class="danger custom-block"><p class="custom-block-title">回滚会丢弃之后的全部代码改动</p><p>代码回滚将工作区恢复至目标快照状态，该消息之后的<strong>所有文件改动都会丢失</strong>，包括你手动编辑的内容。操作前请仔细核对 Diff 预览。</p></div><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解代码检查点之后，可以探索主 Agent 如何派生子 Agent 协同工作，前往<a href="/docs/features/subagents.html">子智能体</a>继续学习。</p>',26)])])}const f=o(l,[["render",i]]);export{g as __pageData,f as default};
